package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetEscapeCharacter_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character escape = format.getEscapeCharacter();
        assertNull(escape, "Default escapeCharacter should be null");
    }

    @Test
    void testGetEscapeCharacter_WithEscapeCharacterSet() {
        CSVFormat format = CSVFormat.DEFAULT.withEscape(Character.valueOf('\\'));
        Character escape = format.getEscapeCharacter();
        assertNotNull(escape, "Escape character should not be null when set");
        assertEquals(Character.valueOf('\\'), escape, "Escape character should be '\\'");
    }

    @Test
    void testGetEscapeCharacter_WithEscapeCharacterSetToNull() {
        CSVFormat format = CSVFormat.DEFAULT.withEscape((Character) null);
        Character escape = format.getEscapeCharacter();
        assertNull(escape, "Escape character should be null when explicitly set to null");
    }

    @Test
    void testGetEscapeCharacter_InformixUnload() {
        CSVFormat format = CSVFormat.INFORMIX_UNLOAD;
        Character escape = format.getEscapeCharacter();
        assertNotNull(escape, "Escape character should not be null");
        assertEquals(Character.valueOf('\\'), escape, "Escape character should be backslash");
    }

    @Test
    void testGetEscapeCharacter_MySQL() {
        CSVFormat format = CSVFormat.MYSQL;
        Character escape = format.getEscapeCharacter();
        assertNotNull(escape, "Escape character should not be null");
        assertEquals(Character.valueOf('\\'), escape, "Escape character should be backslash");
    }

    @Test
    void testGetEscapeCharacter_PostgreSQLCsv() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        Character escape = format.getEscapeCharacter();
        assertNotNull(escape, "Escape character should not be null");
        assertEquals(Character.valueOf('"'), escape, "Escape character should be double quote");
    }

    @Test
    void testGetEscapeCharacter_PostgreSQLText() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        Character escape = format.getEscapeCharacter();
        assertNotNull(escape, "Escape character should not be null");
        assertEquals(Character.valueOf('"'), escape, "Escape character should be double quote");
    }
}
